const output = $json.output;
let parsed;
try {
  parsed = JSON.parse(output);
} catch (e) {
  return [];
}
if (parsed.empty === true || !parsed.txn_id) {
  return [];
}
const candidates = (parsed.candidates || []).slice(0, 3);
while (candidates.length < 3) candidates.push({ id: '', name: '—' });
const token = Math.random().toString(36).slice(2, 10);
const sign = parsed.amount < 0 ? '-' : '+';
const absAmt = (Math.abs(parsed.amount) / 100).toFixed(2);
const account = parsed.account ? `\n🏦 ${parsed.account}` : '';
const text = `📅 ${parsed.date}  •  ${sign}₪${absAmt}\n🏪 ${parsed.payee}${account}\n\nבחר קטגוריה:`;
const inline_keyboard = candidates.map((c, i) => [
  { text: c.name, callback_data: `cat:${token}:${i + 1}` }
]);
inline_keyboard.push([{ text: '✨ סיים', callback_data: `done:${token}` }]);
return {
  token,
  txn_id: parsed.txn_id,
  candidate_ids_json: JSON.stringify(candidates.map(c => c.id)),
  candidate_names_json: JSON.stringify(candidates.map(c => c.name)),
  chat_id: 'MASKED_CHAT_ID',
  text,
  reply_markup: { inline_keyboard },
};

const cbq = $json.callback_query;
const data = cbq?.data || '';
const parts = data.split(':');
const action = parts[0];
const token = parts[1] || '';
const idx = parts[2] ? parseInt(parts[2], 10) : null;
return {
  action,
  token,
  idx,
  chat_id: cbq.message.chat.id,
  message_id: cbq.message.message_id,
  callback_query_id: cbq.id,
};

const cb = $('Extract Token').item.json;
const row = $json;
const chat_id = cb.chat_id;

if (cb.action === 'done') {
  return {
    chatInput: 'השב: סיימנו לעכשיו. תודה!',
    sessionId: `daily_nudge_${chat_id}`,
    isTelegram: true,
  };
}

let ids = [];
let names = [];
try {
  ids = JSON.parse(row.candidate_ids_json || '[]');
  names = JSON.parse(row.candidate_names_json || '[]');
} catch (e) {}
const idx = cb.idx || 1;
const selectedId = ids[idx - 1];
const selectedName = names[idx - 1] || 'ללא שם';
const txn_id = row.txn_id;

if (!selectedId || !txn_id) {
  return {
    chatInput: 'תקלה בזיהוי העסקה. לא הצלחתי לסווג.',
    sessionId: `daily_nudge_${chat_id}`,
    isTelegram: true,
  };
}

// Update + chain to next: single agent invocation. Output the NEXT nudge's JSON
// (so the Route Agent Output Switch will route to Build Nudge Message again),
// or {"empty":true} if no more uncategorized.
const chatInput = `MODE: daily_nudge\n\nראשית: עדכן את העסקה ${txn_id} לקטגוריה ${selectedId} (${selectedName}) באמצעות update-transaction.\nאחר מכן: הרץ מחזור מלא של daily_nudge — הבא עסקה אחת ללא קטגוריה (אל תבחר שוב את ${txn_id} — היא כבר סווגה!) והחזר JSON סטנדרטי של daily_nudge ({txn_id, payee, amount, date, candidates}), או {"empty":true} אם אין עוד.`;

return {
  chatInput,
  sessionId: `daily_nudge_${chat_id}`,
  isTelegram: true,
};

